function Topics() {
  const query = useQuery({
    queryKey: ['topics'],
    queryFn: loadTopics,
    staleTime: 60_000,
  });
  if (query.isPending) return <p>Loading…</p>;
  if (query.isError) return <p>{query.error.message}</p>;
  return query.data.map(topic => <TopicCard key={topic.id} topic={topic} />);
}

